#### 4. Service 계층 (비즈니스 로직)

**위치**: `/user/src/main/kotlin/com/maum/backend/service/follow/` 또는 별도 follow 모듈

```kotlin
@Service
@Transactional
class FollowService(
    private val followRepository: FollowRepository,
    private val userRepository: UserRepository,
) {

    // 팔로우 신청
    fun createFollow(followerId: String, followingId: String): FollowEntity {
        // 자신에게 팔로우 불가
        if (followerId == followingId) {
            throw IllegalArgumentException("Cannot follow yourself")
        }

        // 중복 팔로우 체크
        val existing = followRepository.findByFollowerIdAndFollowingId(followerId, followingId)
        if (existing != null) {
            throw DuplicateFollowException("Already following")
        }

        // 사용자 존재 확인
        userRepository.findById(followingId)
            .orElseThrow { NotFoundException("User not found: $followingId") }

        return followRepository.save(
            FollowEntity(
                followerId = followerId,
                followingId = followingId,
                status = 0 // 요청 대기 상태
            )
        )
    }

    // 팔로우 수락
    @Transactional
    fun approveFollow(followId: String): FollowEntity {
        val follow = followRepository.findById(followId)
            .orElseThrow { NotFoundException("Follow request not found") }

        return followRepository.save(follow.copy(status = 1))
    }

    // 팔로우 거부
    @Transactional
    fun rejectFollow(followId: String) {
        val follow = followRepository.findById(followId)
            .orElseThrow { NotFoundException("Follow request not found") }

        followRepository.delete(follow)
    }

    // 팔로우 취소
    @Transactional
    fun deleteFollow(followerId: String, followingId: String) {
        val follow = followRepository.findByFollowerIdAndFollowingId(followerId, followingId)
            ?: throw NotFoundException("Follow relationship not found")

        followRepository.delete(follow)
    }

    // 팔로워 목록 조회
    @Transactional(readOnly = true)
    fun getFollowers(userId: String, pageable: Pageable): Page<FollowEntity> {
        return followRepository.findActiveFollowersWithPagination(userId, pageable)
    }

    // 팔로우 중 목록 조회
    @Transactional(readOnly = true)
    fun getFollowing(userId: String): List<FollowEntity> {
        return followRepository.findByFollowerIdAndStatus(userId, 1)
    }

    // 팔로우 상태 확인
    @Transactional(readOnly = true)
    fun getFollowStatus(followerId: String, followingId: String): Int {
        return followRepository.findByFollowerIdAndFollowingId(followerId, followingId)
            ?.status ?: -1 // -1 = 팔로우 없음
    }
}
```

#### 5. gRPC Service 구현

**위치**: `/user/src/main/kotlin/com/maum/backend/controller/follow/` (또는 user 모듈의 컨트롤러)

```kotlin
@GrpcService
class FollowGrpcService(
    private val followService: FollowService,
) : FollowServiceGrpc.FollowServiceImplBase() {

    override fun getFollowers(
        request: GetFollowersRequest,
        responseObserver: StreamObserver<GetFollowersResponse>,
    ) {
        try {
            val followers = followService.getFollowers(
                request.userId,
                PageRequest.of(request.offset / request.limit, request.limit)
            )

            val response = GetFollowersResponse.newBuilder()
                .addAllFollowers(followers.content.map { it.toProto() })
                .setTotalCount(followers.totalElements.toInt())
                .build()

            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: NotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Internal error")
                    .asRuntimeException()
            )
        }
    }

    override fun createFollow(
        request: CreateFollowRequest,
        responseObserver: StreamObserver<CreateFollowResponse>,
    ) {
        try {
            val follow = followService.createFollow(
                request.followerId,
                request.followingId
            )

            val response = CreateFollowResponse.newBuilder()
                .setFollow(follow.toProto())
                .build()

            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: StatusRuntimeException) {
            responseObserver.onError(e)
        }
    }

    override fun deleteFollow(
        request: DeleteFollowRequest,
        responseObserver: StreamObserver<DeleteFollowResponse>,
    ) {
        try {
            followService.deleteFollow(
                request.followerId,
                request.followingId
            )

            responseObserver.onNext(DeleteFollowResponse.getDefaultInstance())
            responseObserver.onCompleted()
        } catch (e: NotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        }
    }
}
