#### 7. GraphQL Controller (API Gateway)

**위치**: `/graphql/src/main/kotlin/com/maum/backend/controller/follow/`

```kotlin
@Controller
class FollowController(
    private val followService: FollowService,
    private val userService: UserService,
) {

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun followers(
        @UserId userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): FollowConnection {
        val response = followService.getFollowers(
            userId,
            limit ?: 20,
            offset ?: 0
        )
        return response.toConnection()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun isFollowing(
        @UserId userId: String,
        @Argument targetId: String,
    ): Boolean {
        val status = followService.getFollowStatus(userId, targetId)
        return status == 1 // 1 = 승인된 팔로우
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun createFollow(
        @UserId followerId: String,
        @Argument input: CreateFollowInput,
    ): Follow {
        val follow = followService.createFollow(followerId, input.followingId)
        return follow.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun deleteFollow(
        @UserId followerId: String,
        @Argument followingId: String,
    ): Boolean {
        followService.deleteFollow(followerId, followingId)
        return true
    }
}
